+				{children}
+				{/* Watermark — overlays chart area, pointer-events-none keeps interactions working */}
+				<div
+					className="pointer-events-none select-none absolute bottom-[15%] left-0 right-0 z-10 flex flex-col items-center"
+					aria-hidden="true"
